namespace Em411\Allegro\Api\Model;

class CustomerReturnReturnParcel extends \ArrayObject
{
    /**
     * @var array
     */
    protected $initialized = [];
    /**
     * @var \DateTime|null
     */
    protected $createdAt;
    /**
     * @var string|null
     */
    protected $waybill;
    /**
     * Waybill id as generated by carriers physically transporting the parcel. Will be null if there's only one carrier involved in a parcel shipment.
     *
     * @var string|null
     */
    protected $transportingWaybill;
    /**
     * @var string|null
     */
    protected $carrierId;
    /**
     * Carrier id of a carrier physically transporting the parcel. Will be null if there's only one carrier involved in a parcel shipment.
     *
     * @var string|null
     */
    protected $transportingCarrierId;
    /**
     * @var CustomerReturnParcelSender|null
     */
    protected $sender;

    public function isInitialized($property): bool
    {
        return \array_key_exists($property, $this->initialized);
    }

    public function getCreatedAt(): ?\DateTime
    {
        return $this->createdAt;
    }

    public function setCreatedAt(?\DateTime $createdAt): self
    {
        $this->initialized['createdAt'] = true;
        $this->createdAt = $createdAt;

        return $this;
    }

    public function getWaybill(): ?string
    {
        return $this->waybill;
    }

    public function setWaybill(?string $waybill): self
    {
        $this->initialized['waybill'] = true;
        $this->waybill = $waybill;

        return $this;
    }

    /**
     * Waybill id as generated by carriers physically transporting the parcel. Will be null if there's only one carrier involved in a parcel shipment.
     */
    public function getTransportingWaybill(): ?string
    {
        return $this->transportingWaybill;
    }

    /**
     * Waybill id as generated by carriers physically transporting the parcel. Will be null if there's only one carrier involved in a parcel shipment.
     */
    public function setTransportingWaybill(?string $transportingWaybill): self
    {
        $this->initialized['transportingWaybill'] = true;
        $this->transportingWaybill = $transportingWaybill;

        return $this;
    }

    public function getCarrierId(): ?string
    {
        return $this->carrierId;
    }

    public function setCarrierId(?string $carrierId): self
    {
        $this->initialized['carrierId'] = true;
        $this->carrierId = $carrierId;

        return $this;
    }

    /**
     * Carrier id of a carrier physically transporting the parcel. Will be null if there's only one carrier involved in a parcel shipment.
     */
    public function getTransportingCarrierId(): ?string
    {
        return $this->transportingCarrierId;
    }

    /**
     * Carrier id of a carrier physically transporting the parcel. Will be null if there's only one carrier involved in a parcel shipment.
     */
    public function setTransportingCarrierId(?string $transportingCarrierId): self
    {
        $this->initialized['transportingCarrierId'] = true;
        $this->transportingCarrierId = $transportingCarrierId;

        return $this;
    }

    public function getSender(): ?CustomerReturnParcelSender
    {
        return $this->sender;
    }

    public function setSender(?CustomerReturnParcelSender $sender): self
    {
        $this->initialized['sender'] = true;
        $this->sender = $sender;

        return $this;
    }
}
